operations.content:
.worldcup-page {
  --field-green: #0b6b3d;
  --field-deep: #063823;
  --brand-yellow: #fcda00;
  --gold-line: #dbaf00;
  --ink: #123326;
  --muted: #61776c;
  --lime: #24b35d;
  --coral: #f06445;
  --sky: #3a91ff;
  position: relative;
  width: min(100%, 375px);
  min-height: 1460px;
  margin: 0 auto;
  overflow: hidden;
  color: var(--ink);
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  background:
    radial-gradient(120% 38% at 50% -7%, rgba(255, 243, 177, 0.82), transparent 62%),
    linear-gradient(180deg, rgba(4, 36, 27, 0) 0, rgba(4, 36, 27, 0.15) 300px, rgba(4, 36, 27, 0.38) 560px),
    url("../../assets/football/home/hero-bg-figma.webp"),
    linear-gradient(180deg, #11784a 0%, #0b6b3d 42%, #063823 100%);
  background-repeat: no-repeat;
  background-position: top center;
  background-size: 100% 430px, 100% 620px, 100% auto, 100% 100%;
}

.worldcup-page::before {
  content: "";
  position: absolute;
  inset: 700px 0 0;
  opacity: 0.32;
  pointer-events: none;
  background-image:
    linear-gradient(90deg, transparent 49.5%, rgba(255, 255, 255, 0.24) 50%, transparent 50.5%),
    repeating-linear-gradient(180deg, rgba(255,255,255,0.08) 0, rgba(255,255,255,0.08) 1px, transparent 1px, transparent 54px);
}

.worldcup-page button {
  appearance: none;
  border: 0;
  padding: 0;
  font: inherit;
}

.topbar {
  position: absolute;
  top: 14px;
  left: 0;
  right: 0;
  z-index: 5;
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  height: 98px;
  pointer-events: none;
}

.topbar-icon-btn {
  display: grid;
  place-items: center;
  width: 60px;
  height: 60px;
  background: transparent;
  pointer-events: auto;
}

.topbar-icon-btn img {
  display: block;
  width: 60px;
  height: 60px;
}

.topbar-actions {
  position: relative;
  display: grid;
  justify-items: end;
  pointer-events: auto;
}

.topbar-rule-btn {
  position: absolute;
  top: 64px;
  right: 0;
  min-width: 44px;
  height: 24px;
  padding: 0 12px 0 10px;
  border-radius: 999px 0 0 999px;
  border: 1px solid rgba(255,255,255,0.48);
  border-right: 0;
  background: rgba(4, 38, 28, 0.58);
  color: #fff;
  font-size: 12px;
  font-weight: 800;
  box-shadow: 0 5px 14px rgba(0,0,0,0.18);
}

.hero {
  position: relative;
  z-index: 1;
  min-height: 430px;
  padding: 0 5px;
}

.confetti {
  position: absolute;
  inset: 0;
  pointer-events: none;
}

.confetti span {
  position: absolute;
  width: 10px;
  height: 6px;
  border-radius: 999px;
  background: #43b35a;
  transform: rotate(-8deg);
}

.confetti span:nth-child(1) { left: 86px; top: 58px; width: 8px; height: 15px; background: #f4d20d; }
.confetti span:nth-child(2) { left: 112px; top: 50px; width: 22px; background: #31a75b; }
.confetti span:nth-child(3) { left: 186px; top: 48px; width: 15px; height: 9px; background: #f4d20d; }
.confetti span:nth-child(4) { left: 246px; top: 22px; width: 16px; height: 13px; background: #e2c715; transform: rotate(-16deg); }
.confetti span:nth-child(5) { left: 305px; top: 42px; width: 21px; background: #35a75b; }
.confetti span:nth-child(6) { left: 344px; top: 68px; width: 18px; background: #f4d20d; }
.confetti span:nth-child(7) { left: 72px; top: 110px; width: 16px; height: 16px; border-radius: 50%; background: #f4d20d; }
.confetti span:nth-child(8) { left: 154px; top: 128px; width: 18px; height: 10px; background: #8ad48c; }
.confetti span:nth-child(9) { left: 208px; top: 118px; width: 15px; height: 15px; background: #52ad74; transform: rotate(45deg); }
.confetti span:nth-child(10) { left: 270px; top: 84px; width: 21px; background: #f4d20d; }
.confetti span:nth-child(11) { left: 326px; top: 110px; width: 18px; background: #42b25a; }
.confetti span:nth-child(12) { left: 121px; top: 88px; width: 8px; height: 14px; background: #42b25a; }

.hero-title-art {
  position: absolute;
  top: 82px;
  left: 50%;
  z-index: 2;
  display: block;
  width: min(335px, 89.28vw);
  height: auto;
  transform: translateX(-50%);
  filter: drop-shadow(0 12px 16px rgba(0, 48, 22, 0.18));
}

.phase-strip {
  position: absolute;
  left: 13px;
  right: 13px;
  bottom: 24px;
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 24px;
  margin: 0;
  padding: 3px 12px 4px;
  border-radius: 17px;
  background: #08692f;
  color: #fff;
  font-size: 12px;
  font-weight: 600;
  line-height: 17px;
  text-align: center;
}

.phase-strip strong {
  color: var(--brand-yellow);
  font-weight: 800;
}

.task-card {
  position: relative;
  z-index: 2;
  margin: -18px 0 16px;
  padding: 0 18px;
  color: #fff;
}

.task-card-head {
  display: grid;
  grid-template-columns: 48px minmax(0, 1fr) auto;
  align-items: center;
  gap: 8px;
  min-height: 64px;
}

.avatar-ring {
  display: grid;
  place-items: center;
  width: 48px;
  height: 48px;
  border-radius: 50%;
  border: 2px solid rgba(162, 230, 174, 0.96);
  background: rgba(255,255,255,0.1);
}

.avatar-silhouette {
  position: relative;
  display: block;
  width: 30px;
  height: 30px;
  border-radius: 50%;
  background: #ffffff;
}

.avatar-silhouette::before,
.avatar-silhouette::after {
  content: "";
  position: absolute;
  left: 50%;
  transform: translateX(-50%);
  background: #ffffff;
}

.avatar-silhouette::before {
  top: -2px;
  width: 15px;
  height: 15px;
  border-radius: 50%;
}

.avatar-silhouette::after {
  bottom: 0;
  width: 34px;
  height: 16px;
  border-radius: 36px 36px 10px 10px;
}

.task-user-info span {
  display: block;
  color: var(--brand-yellow);
  font-size: 10px;
  font-weight: 500;
  line-height: 1.2;
}

.task-user-info h1 {
  margin: 5px 0 0;
  color: #fff;
  font-size: 16px;
  font-weight: 600;
  line-height: 1.2;
  letter-spacing: 0;
}

.task-prize-entry {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 5px;
  width: 122px;
  min-height: 32px;
  padding: 6px 8px;
  border-radius: 999px;
  background: rgba(0,0,0,0.3);
  color: #fff;
  font-size: 13px;
  font-weight: 600;
}

.task-prize-entry img {
  width: 20px;
  height: 20px;
}

.task-prize-entry strong {
  display: grid;
  place-items: center;
  min-width: 20px;
  height: 20px;
  border-radius: 50%;
  background: var(--brand-yellow);
  color: #544300;
  font-size: 14px;
  font-weight: 500;
}

.task-panel {
  position: relative;
  margin-top: 22px;
  padding: 34px 14px 20px;
  border: 8px solid #008327;
  border-radius: 14px;
  background: #fffefa;
  color: #0b6b28;
  box-shadow: inset 0 0 0 1px rgba(255,255,255,0.8);
}

.task-panel::before,
.task-panel::after {
  content: "";
  position: absolute;
  left: 15px;
  right: 15px;
  height: 22px;
  border-radius: 4px;
  background: #80b98a;
  box-shadow: 0 5px 0 rgba(41, 95, 48, 0.28), inset 0 -2px 0 rgba(0,0,0,0.18), inset 0 2px 0 rgba(255,255,255,0.3);
}

.task-panel::before { top: -10px; }
.task-panel::after {
  top: -28px;
  left: 50%;
  right: auto;
  width: 46px;
  height: 30px;
  border-radius: 42px 42px 0 0;
  transform: translateX(-50%);
  background: #7caf82;
}

.task-clip {
  position: absolute;
  top: -30px;
  left: 22px;
  right: 22px;
  z-index: 2;
  width: calc(100% - 44px);
  height: auto;
  pointer-events: none;
}

.task-list {
  display: grid;
  gap: 8px;
  margin: 0;
  padding: 0;
  list-style: none;
}

.task-item {
  display: grid;
  grid-template-columns: 40px minmax(0, 1fr) 30px;
  align-items: center;
  gap: 10px;
  min-height: 56px;
}

.task-item img {
  width: 40px;
  height: 40px;
  object-fit: contain;
}

.task-item strong {
  display: block;
  color: #0a7a25;
  font-size: 18px;
  font-weight: 600;
  line-height: 1.18;
}

.task-item span {
  display: block;
  margin-top: 4px;
  color: #454545;
  font-size: 12px;
  line-height: 1.18;
}

.task-item b {
  display: inline-block;
  margin-right: 8px;
  padding: 0 8px;
  border-radius: 7px;
  background: #ffe25a;
  color: #544300;
  font-size: 12px;
  line-height: 1.35;
}

.task-item u {
  color: #0a7a25;
  text-underline-offset: 3px;
}

.task-item em {
  display: block;
  justify-self: end;
  width: 30px;
  height: 30px;
  border: 0;
  border-radius: 50%;
  background: url("../../assets/football/home/task-check-off-646542.webp") center / contain no-repeat;
  transform: none;
}

.task-primary-action {
  display: grid;
  place-items: center;
  width: 100%;
  min-height: 47px;
  height: 47px;
  width: calc(100% - 40px);
  margin: 8px auto 0;
  border: 2px solid var(--gold-line);
  border-radius: 10px;
  background: var(--brand-yellow);
  color: #6a5300;
  font-size: 18px;
  font-weight: 500;
  box-shadow: inset 0 2px 0 rgba(255,255,255,0.28);
}

.teams-section,
.prize-showcase,
.bottom-share {
  position: relative;
  z-index: 2;
  margin: 24px 18px 0;
}

.section-title-art {
  display: block;
  width: min(100%, 342px);
  height: auto;
  margin: 0 auto 13px;
}

.team-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 10px;
}

.team-card {
  position: relative;
  display: flex;
  min-height: 130px;
  flex-direction: column;
  align-items: center;
  padding: 12px 6px 10px;
  border: 1px solid rgba(255,255,255,0.76);
  border-radius: 14px;
  background: linear-gradient(180deg, rgba(255,255,255,0.98), rgba(243,250,246,0.96));
  box-shadow: 0 12px 22px rgba(1,37,24,0.14), inset 0 1px 0 rgba(255,255,255,0.92);
  overflow: hidden;
}

.team-card::before {
  content: "";
  position: absolute;
  top: 0;
  right: 0;
  left: 0;
  height: 5px;
  background: linear-gradient(90deg, var(--lime), var(--brand-yellow) 52%, var(--coral));
}

.team-avatar {
  display: grid;
  place-items: center;
  width: 58px;
  height: 58px;
  border: 3px solid #fff;
  border-radius: 50%;
  background: linear-gradient(145deg, var(--team-from), var(--team-to));
  box-shadow: 0 8px 16px rgba(0,0,0,0.17), 0 0 0 2px rgba(8,96,56,0.08);
  overflow: hidden;
}

.team-avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.team-name {
  width: 100%;
  margin-top: 9px;
  overflow: hidden;
  color: var(--ink);
  font-size: 14px;
  font-weight: 900;
  line-height: 1.2;
  text-align: center;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.team-role {
  display: -webkit-box;
  width: 100%;
  margin-top: 4px;
  overflow: hidden;
  color: #527066;
  font-size: 11px;
  font-weight: 800;
  line-height: 1.25;
  text-align: center;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: 2;
}

.section-title-art--prize {
  margin-bottom: 10px;
}

.prize-scroll {
  display: flex;
  gap: 10px;
  overflow-x: hidden;
  padding: 0 0 2px;
}

.prize-showcase-item {
  flex: 0 0 107px;
  display: grid;
  justify-items: center;
  gap: 5px;
  min-height: 142px;
  padding: 10px 8px 9px;
  border: 1px solid rgba(18,101,65,0.1);
  border-radius: 16px;
  background: linear-gradient(180deg, rgba(255,255,255,0.9), rgba(239,249,243,0.98)), #f3fbf6;
  color: inherit;
  text-align: center;
}

.prize-showcase-art {
  display: grid;
  place-items: center;
  width: 82px;
  height: 74px;
  border: 1px solid rgba(18,101,65,0.1);
  border-radius: 18px;
  background: radial-gradient(circle at 50% 28%, rgba(255,212,71,0.5), transparent 56%), #edf8f2;
  overflow: hidden;
}

.prize-showcase-art img {
  width: 100%;
  height: 100%;
  object-fit: contain;
}

.prize-showcase-item strong {
  color: var(--ink);
  font-size: 14px;
  font-weight: 900;
  line-height: 1.12;
}

.prize-showcase-item > span:last-child {
  color: var(--muted);
  font-size: 11px;
  font-weight: 800;
  line-height: 1.2;
}

.bottom-share {
  display: grid;
  gap: 12px;
  padding: 18px 16px 22px;
  border-radius: 18px;
  background: rgba(255,255,255,0.12);
  color: #fff;
}

.bottom-share img {
  display: block;
  width: 240px;
  max-width: 100%;
  margin: 0 auto;
}

.share-actions {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
}

.share-button {
  min-height: 46px;
  border-radius: 999px;
  font-size: 15px;
  font-weight: 900;
}

.share-button--friend {
  background: #31b766;
  color: #fff;
}

.share-button--moments {
  background: #fff;
  color: #126541;
}

@media (max-width: 360px) {
  .worldcup-page {
    width: 100%;
  }

  .phase-strip {
    font-size: 20px;
  }

  .task-card {
    margin-left: 14px;
    margin-right: 14px;
  }

  .task-card-head {
    grid-template-columns: 84px minmax(0, 1fr);
  }

  .task-prize-entry {
    grid-column: 2;
    justify-self: start;
    margin-top: 8px;
  }

  .task-panel {
    padding-left: 22px;
    padding-right: 22px;
  }

  .task-item {
    grid-template-columns: 54px minmax(0, 1fr) 48px;
    gap: 10px;
  }

  .task-item strong,
  .task-primary-action {
    font-size: 27px;
  }

  .task-item span {
    font-size: 19px;
  }
}

.task-item.is-on em {
  background-image: url("../../assets/football/home/task-check-on-68ebf7.webp");
}

.task-item.is-locked {
  opacity: 0.55;
}

.state-note,
.supported-team,
.skin-unlocked,
.mini-prize-strip {
  margin: 12px auto 0;
  width: calc(100% - 22px);
  border-radius: 12px;
  background: #eef9ef;
  border: 1px solid rgba(11, 107, 61, 0.12);
  color: #126541;
}

.state-note {
  display: grid;
  gap: 3px;
  padding: 10px 12px;
}

.state-note strong,
.supported-team strong,
.skin-unlocked strong {
  font-size: 14px;
  line-height: 1.2;
}

.state-note span,
.supported-team span,
.skin-unlocked span {
  color: #527066;
  font-size: 12px;
  line-height: 1.35;
}

.state-note--gold {
  background: #fff7cf;
  color: #7a5f00;
  border-color: rgba(219, 175, 0, 0.24);
}

.supported-team,
.skin-unlocked {
  display: grid;
  grid-template-columns: 46px minmax(0, 1fr);
  gap: 10px;
  align-items: center;
  padding: 8px 10px;
}

.supported-team img,
.skin-unlocked img {
  width: 46px;
  height: 46px;
  border-radius: 12px;
  object-fit: cover;
  background: #fff;
}

.skin-unlocked img {
  border-radius: 10px;
  object-fit: contain;
}

.mini-prize-strip {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;
  padding: 8px;
}

.mini-prize-strip span {
  display: grid;
  grid-template-columns: 34px minmax(0, 1fr);
  align-items: center;
  gap: 6px;
  min-height: 42px;
  padding: 4px 6px;
  border-radius: 10px;
  background: #fff;
  color: #126541;
  font-size: 12px;
  font-weight: 800;
}

.mini-prize-strip img {
  width: 34px;
  height: 34px;
  object-fit: contain;
}

.team-card.is-supported {
  border-color: rgba(252, 218, 0, 0.95);
  box-shadow: 0 12px 22px rgba(1,37,24,0.14), 0 0 0 3px rgba(252,218,0,0.28);
}

.is-upcoming .task-primary-action,
.is-used .task-primary-action,
.is-ended.is-lost .task-primary-action {
  background: #e8efe8;
  border-color: #c5d7c5;
  color: #527066;
}

.is-ended .worldcup-page,
.worldcup-page.is-ended {
  background-size: 100% 430px, 100% 620px, 100% auto, 100% 100%;
}

.worldcup-page.is-ended .phase-strip {
  background: #143a31;
}
